import{_ as o,o as l,c as i,a3 as s}from"./chunks/framework.BTFg6ESq.js";const u=JSON.parse('{"title":"故障排除指南","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/troubleshooting.md","filePath":"user-guide/troubleshooting.md","lastUpdated":1782242244000}'),a={name:"user-guide/troubleshooting.md"};function e(r,t,n,g,h,d){return l(),i("div",null,[...t[0]||(t[0]=[s('<h1 id="故障排除指南" tabindex="-1">故障排除指南 <a class="header-anchor" href="#故障排除指南" aria-label="Permalink to &quot;故障排除指南&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>使用 AIO Hub 过程中遇到问题？别着急。本指南汇总了最常见的故障类型和对应的解决方法，你可以根据自己的情况快速定位问题。</p><blockquote><p>💡 <strong>自助排查原则</strong>：遇到问题先重启应用——很多临时问题重启就能解决。如果重启无效，再按本指南的步骤逐一排查。</p></blockquote><hr><h2 id="安装问题" tabindex="-1">安装问题 <a class="header-anchor" href="#安装问题" aria-label="Permalink to &quot;安装问题&quot;">​</a></h2><h3 id="windows-安装时提示-无法验证发布者" tabindex="-1">Windows 安装时提示 &quot;无法验证发布者&quot; <a class="header-anchor" href="#windows-安装时提示-无法验证发布者" aria-label="Permalink to &quot;Windows 安装时提示 &quot;无法验证发布者&quot;&quot;">​</a></h3><p><strong>症状</strong>：安装时 Windows 弹出安全警告，显示&quot;Windows 保护了你的电脑&quot;。</p><p><strong>原因</strong>：AIO Hub 的安装包尚未完成微软的签名认证流程，这是首次安装未签名应用时的正常提示。</p><p><strong>解决步骤</strong>：</p><ol><li>在安全警告弹窗中，点击 <strong>&quot;更多信息&quot;</strong>（蓝色文字链接）</li><li>底部会出现 <strong>&quot;仍要运行&quot;</strong> 按钮，点击即可继续安装</li><li>安装完成后不会再弹出此提示</li></ol><blockquote><p>如果你还是不放心，可以查看项目在 GitHub 上的开源代码，或对照 Releases 页面提供的 SHA-256 校验码验证文件完整性。</p></blockquote><h3 id="macos-安装后提示-应用已损坏-无法打开" tabindex="-1">macOS 安装后提示 &quot;应用已损坏，无法打开&quot; <a class="header-anchor" href="#macos-安装后提示-应用已损坏-无法打开" aria-label="Permalink to &quot;macOS 安装后提示 &quot;应用已损坏，无法打开&quot;&quot;">​</a></h3><p><strong>症状</strong>：从官网下载的 <code>.dmg</code> 安装完成后，双击应用提示&quot;应用已损坏，无法打开。你应该将它移到废纸篓&quot;。</p><p><strong>原因</strong>：macOS Gatekeeper 安全机制拦截了未经 Apple 公证的第三方应用。<strong>这不是应用本身的问题</strong>。</p><p><strong>解决步骤</strong>：</p><p><strong>方法一（推荐）</strong>：</p><ol><li>在 <code>应用程序</code> 文件夹中找到 AIO Hub</li><li>按住 <code>Control</code> 键，同时右键点击应用图标</li><li>选择 <strong>&quot;打开&quot;</strong></li><li>在弹出的确认弹窗中点击 <strong>&quot;打开&quot;</strong></li><li>之后就可以正常双击打开了</li></ol><p><strong>方法二（如果方法一无效）</strong>：</p><ol><li>打开 <strong>终端（Terminal）</strong></li><li>执行以下命令（需要输入开机密码）：<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xattr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -cr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /Applications/AIO</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Hub.app</span></span></code></pre></div></li><li>完成后重新启动应用</li></ol><blockquote><p>更详细的说明请参考 <a href="./faq/macos-gatekeeper-fix">macOS Gatekeeper 修复指南</a>。</p></blockquote><h3 id="linux-安装后无法启动-无反应" tabindex="-1">Linux 安装后无法启动（无反应） <a class="header-anchor" href="#linux-安装后无法启动-无反应" aria-label="Permalink to &quot;Linux 安装后无法启动（无反应）&quot;">​</a></h3><p><strong>症状</strong>：双击 AppImage 文件后没有任何反应。</p><p><strong>原因</strong>：AppImage 文件没有执行权限。</p><p><strong>解决步骤</strong>：</p><ol><li>在终端中执行：<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AIO-Hub_</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.AppImage</span></span></code></pre></div></li><li>或者右键文件 → <strong>属性 → 权限</strong>，勾选 <strong>&quot;允许以程序执行文件&quot;</strong></li><li>再双击运行即可</li></ol><blockquote><p>如果依然无法启动，尝试从终端运行查看错误输出：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./AIO-Hub_*.AppImage</span></span></code></pre></div></blockquote><hr><h2 id="运行问题" tabindex="-1">运行问题 <a class="header-anchor" href="#运行问题" aria-label="Permalink to &quot;运行问题&quot;">​</a></h2><h3 id="应用启动后白屏-界面空白" tabindex="-1">应用启动后白屏 / 界面空白 <a class="header-anchor" href="#应用启动后白屏-界面空白" aria-label="Permalink to &quot;应用启动后白屏 / 界面空白&quot;">​</a></h3><p><strong>症状</strong>：应用能打开，但界面完全空白，没有任何内容。</p><p><strong>原因</strong>：</p><ul><li><strong>系统组件缺失</strong>：在 Windows 上可能表现为 WebView2 损坏或缺失（现代系统较少见）；在 Linux 上则更为常见，通常是由于缺少必要的 WebKit 依赖库。</li><li><strong>系统显卡驱动过旧</strong>：显卡驱动不支持硬件加速渲染。</li></ul><p><strong>解决步骤</strong>：</p><ol><li><strong>Windows 用户</strong>：检查 WebView2 状态。若系统较老或为精简版，可尝试手动安装：<a href="https://developer.microsoft.com/zh-cn/microsoft-edge/webview2/" target="_blank" rel="noreferrer">下载 Microsoft Edge WebView2 Runtime</a>。</li><li><strong>Linux 用户</strong>：确保已安装 <code>webkit2gtk</code> 等必要的系统库。</li><li><strong>更新显卡驱动</strong>：前往你的显卡厂商官网（NVIDIA / AMD / Intel）下载最新驱动</li><li><strong>尝试禁用硬件加速</strong>：如果应用能进入设置页面，前往 <strong>设置 → 外观</strong>，关闭硬件加速</li></ol><h3 id="应用频繁闪退" tabindex="-1">应用频繁闪退 <a class="header-anchor" href="#应用频繁闪退" aria-label="Permalink to &quot;应用频繁闪退&quot;">​</a></h3><p><strong>症状</strong>：使用过程中应用突然关闭，没有任何提示。</p><p><strong>原因</strong>：可能是内存不足、系统兼容问题或特定操作触发了异常。</p><p><strong>解决步骤</strong>：</p><ol><li><strong>重启应用</strong>：先试最基础的方法</li><li><strong>查看系统资源</strong>：打开任务管理器（Windows）或活动监视器（macOS），确认内存和 CPU 使用率是否过高</li><li><strong>清理缓存</strong>：关闭应用后，手动删除缓存目录中的数据（注意：这不会删除你的配置和聊天记录） <ul><li>Windows：<code>%APPDATA%\\com.mty.aiohub\\cache</code></li><li>macOS：<code>~/Library/Caches/com.mty.aiohub</code></li><li>Linux：<code>~/.cache/com.mty.aiohub</code></li></ul></li><li><strong>查看日志</strong>：如果闪退频繁，查看日志文件中的错误信息： <ul><li>Windows：打开 <code>%APPDATA%\\com.mty.aiohub\\logs\\</code> 文件夹，找到最新的 <code>.log</code> 文件</li><li>macOS：打开 <code>~/Library/Logs/com.mty.aiohub/</code> 文件夹</li><li>Linux：打开 <code>~/.local/share/com.mty.aiohub/logs/</code> 文件夹</li></ul></li><li><strong>反馈问题</strong>：将日志文件中的相关错误信息截图或复制，到 <a href="https://github.com/miaotouy/aio-hub/issues" target="_blank" rel="noreferrer">GitHub Issues</a> 反馈，开发者可以快速定位问题</li></ol><h3 id="应用运行缓慢-卡顿" tabindex="-1">应用运行缓慢 / 卡顿 <a class="header-anchor" href="#应用运行缓慢-卡顿" aria-label="Permalink to &quot;应用运行缓慢 / 卡顿&quot;">​</a></h3><p><strong>症状</strong>：界面操作响应慢，切换页面有明显延迟。</p><p><strong>原因</strong>：</p><ul><li>打开了过多工具或标签页</li><li>长时间运行未重启，内存累积占用过高</li><li>系统资源不足</li></ul><p><strong>解决步骤</strong>：</p><ol><li><strong>关闭不用的工具页</strong>：只保留当前正在使用的工具</li><li><strong>重启应用</strong>：释放累积的内存占用</li><li><strong>检查后台任务</strong>：如果有大量的队列任务或数据处理任务在后台运行，等待它们完成或手动取消</li><li><strong>降低界面特效</strong>：前往 <strong>设置 → 外观</strong>，关闭毛玻璃效果和界面效果，可以减少 GPU 负担</li><li><strong>可能存在漏洞</strong>: 收集相关信息到 <strong>issues</strong> 中反馈</li></ol><h3 id="开启毛玻璃效果后界面闪烁" tabindex="-1">开启毛玻璃效果后界面闪烁 <a class="header-anchor" href="#开启毛玻璃效果后界面闪烁" aria-label="Permalink to &quot;开启毛玻璃效果后界面闪烁&quot;">​</a></h3><p><strong>症状</strong>：开启毛玻璃（透明模糊）效果后，窗口或部分区域闪烁、渲染异常。</p><p><strong>原因</strong>：显卡驱动兼容性问题，或系统不支持该特效。</p><p><strong>解决步骤</strong>：</p><ol><li>前往 <strong>设置 → 外观</strong>，将 <strong>&quot;界面质感&quot;</strong> 调整为 <strong>&quot;纯色&quot;</strong> 模式</li><li>如果问题消失，说明是显卡驱动问题。尝试更新显卡驱动到最新版本</li><li>如果更新驱动后问题依然存在，保持&quot;纯色&quot;模式使用，不影响核心功能</li></ol><hr><h2 id="网络问题" tabindex="-1">网络问题 <a class="header-anchor" href="#网络问题" aria-label="Permalink to &quot;网络问题&quot;">​</a></h2><h3 id="llm-对话时提示-连接超时-或-请求失败" tabindex="-1">LLM 对话时提示 &quot;连接超时&quot; 或 &quot;请求失败&quot; <a class="header-anchor" href="#llm-对话时提示-连接超时-或-请求失败" aria-label="Permalink to &quot;LLM 对话时提示 &quot;连接超时&quot; 或 &quot;请求失败&quot;&quot;">​</a></h3><p><strong>症状</strong>：在聊天或任何使用 AI 服务的工具中，请求一直转圈，最终提示连接超时。</p><p><strong>原因</strong>：</p><ul><li>API 服务提供商在中国大陆访问不稳定（如 OpenAI）</li><li>代理配置不正确或系统的其他网络问题</li><li>上游服务存在问题，尝试切换服务商</li></ul><p><strong>解决步骤</strong>：</p><ol><li><strong>检查代理配置</strong>： <ul><li>如果你需要走代理访问 API，请在 <strong>设置 → 通用设置 → 网络代理</strong> 中配置 HTTP 代理</li><li>注意代理地址的格式：<code>http://127.0.0.1:端口号</code>，不要漏掉 <code>http://</code></li></ul></li><li><strong>检查网络连接</strong>：打开浏览器访问 <a href="https://www.baidu.com" target="_blank" rel="noreferrer">https://www.baidu.com</a> 确认网络正常</li><li><strong>尝试直连</strong>：如果配置了代理，先关闭代理试试直连是否能正常工作</li><li><strong>更换模型服务商</strong>：如果某个服务商稳定性差，可以尝试其他可用的服务商</li></ol><h3 id="提示-ssl-证书错误" tabindex="-1">提示 &quot;SSL 证书错误&quot; <a class="header-anchor" href="#提示-ssl-证书错误" aria-label="Permalink to &quot;提示 &quot;SSL 证书错误&quot;&quot;">​</a></h3><p><strong>症状</strong>：请求 API 时返回 SSL 相关的错误信息。</p><p><strong>原因</strong>：</p><ul><li>系统时间不准确</li><li>代理软件拦截了 SSL 证书</li><li>企业网络环境中使用了自签名证书</li></ul><p><strong>解决步骤</strong>：</p><ol><li><strong>校准系统时间</strong>：确保电脑的日期和时间是正确的</li><li><strong>检查代理</strong>：如果使用了第三方代理软件，尝试暂时关闭或切换代理模式</li><li><strong>尝试更换网络</strong>：切换到手机热点或其他网络，排除企业网络限制</li><li><strong>在设置中调整</strong>：前往 <strong>设置 → 网络</strong>，查看是否有 SSL 验证相关的选项</li></ol><h3 id="图片或文件上传失败" tabindex="-1">图片或文件上传失败 <a class="header-anchor" href="#图片或文件上传失败" aria-label="Permalink to &quot;图片或文件上传失败&quot;">​</a></h3><p><strong>症状</strong>：上传附件或图片时转圈后失败。</p><p><strong>原因</strong>：</p><ul><li>文件过大</li><li>网络上传速度慢</li><li>存储空间不足</li></ul><p><strong>解决步骤</strong>：</p><ol><li><strong>检查文件大小</strong>：尝试上传小文件（1MB 以下），如果成功说明是文件大小限制</li><li><strong>检查磁盘空间</strong>：确认系统盘还有足够的剩余空间</li><li><strong>重启应用</strong>：偶尔是临时网络波动，重试即可</li></ol><hr><h2 id="数据问题" tabindex="-1">数据问题 <a class="header-anchor" href="#数据问题" aria-label="Permalink to &quot;数据问题&quot;">​</a></h2><h3 id="意外关闭后数据丢失" tabindex="-1">意外关闭后数据丢失 <a class="header-anchor" href="#意外关闭后数据丢失" aria-label="Permalink to &quot;意外关闭后数据丢失&quot;">​</a></h3><p><strong>症状</strong>：应用意外退出后，重启发现部分对话记录或配置丢失。</p><p><strong>原因</strong>：</p><ul><li>数据尚未完成自动保存</li><li>配置文件损坏</li></ul><p><strong>解决步骤</strong>：</p><ol><li><strong>检查自动保存</strong>：AIO Hub 会在操作过程中自动保存数据。如果只是个别最近的对话丢失，属于正常现象</li><li><strong>查看日志文件</strong>：在日志目录中检查是否有 <code>storage</code> 相关的错误信息</li><li><strong>备份恢复</strong>：如果你之前手动备份过数据，可以将备份文件复制回数据目录覆盖</li></ol><p><strong>数据目录位置</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">平台</th><th style="text-align:left;">路径</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Windows</strong></td><td style="text-align:left;"><code>%APPDATA%\\com.mty.aiohub</code></td></tr><tr><td style="text-align:left;"><strong>macOS</strong></td><td style="text-align:left;"><code>~/Library/Application Support/com.mty.aiohub</code></td></tr><tr><td style="text-align:left;"><strong>Linux</strong></td><td style="text-align:left;"><code>~/.local/share/com.mty.aiohub</code></td></tr></tbody></table><h3 id="如何手动备份数据" tabindex="-1">如何手动备份数据 <a class="header-anchor" href="#如何手动备份数据" aria-label="Permalink to &quot;如何手动备份数据&quot;">​</a></h3><p><strong>建议定期备份</strong>，特别是当你有重要的对话记录或配置时。</p><p><strong>手动备份步骤</strong>：</p><ol><li>关闭 AIO Hub（确保数据文件没有被占用）</li><li>找到你的数据目录（见上表）</li><li>复制整个目录到安全位置（如移动硬盘、云盘）</li><li><strong>恢复时</strong>：同样先关闭应用，将备份的目录覆盖回原位置即可</li></ol><blockquote><p>📅 <strong>建议频率</strong>：如果你重度使用 AI 对话，建议每周备份一次。只在本地使用的话，每月备份一次已经足够。</p></blockquote><h3 id="配置修改后恢复默认值" tabindex="-1">配置修改后恢复默认值 <a class="header-anchor" href="#配置修改后恢复默认值" aria-label="Permalink to &quot;配置修改后恢复默认值&quot;">​</a></h3><p><strong>症状</strong>：修改了某个设置后，应用行为异常，或者想回到最初的状态。</p><p><strong>解决步骤</strong>：</p><ol><li>关闭 AIO Hub</li><li>找到数据目录中的配置文件（通常是 <code>config.json</code> 或 <code>settings.json</code>）</li><li>将该文件重命名（例如改为 <code>config.json.bak</code>）</li><li>重新启动应用——它会自动生成一份新的默认配置文件</li><li>如果问题解决，你可以手动对照备份文件，只迁移重要的设置项</li></ol><blockquote><p>⚠️ 注意：此操作会丢失你的所有设置，建议先完整备份整个数据目录。</p></blockquote><hr><h2 id="常见问题-faq" tabindex="-1">常见问题 (FAQ) <a class="header-anchor" href="#常见问题-faq" aria-label="Permalink to &quot;常见问题 (FAQ)&quot;">​</a></h2><h3 id="q1-在哪里可以找到应用的错误日志" tabindex="-1">Q1：在哪里可以找到应用的错误日志？ <a class="header-anchor" href="#q1-在哪里可以找到应用的错误日志" aria-label="Permalink to &quot;Q1：在哪里可以找到应用的错误日志？&quot;">​</a></h3><p>日志文件是排查问题的关键。按你的平台找到对应路径：</p><table tabindex="0"><thead><tr><th style="text-align:left;">平台</th><th style="text-align:left;">日志路径</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Windows</strong></td><td style="text-align:left;"><code>%APPDATA%\\com.mty.aiohub\\logs\\</code></td></tr><tr><td style="text-align:left;"><strong>macOS</strong></td><td style="text-align:left;"><code>~/Library/Logs/com.mty.aiohub/</code></td></tr><tr><td style="text-align:left;"><strong>Linux</strong></td><td style="text-align:left;"><code>~/.local/share/com.mty.aiohub/logs/</code></td></tr></tbody></table><p>日志文件按日期命名（如 <code>app-2025-05-07.log</code>），最新的问题可以在最新日期的文件中找到。如果你需要向开发者反馈问题，请附上相关日志内容。</p><h3 id="q2-如何确认我下载的版本是最新的" tabindex="-1">Q2：如何确认我下载的版本是最新的？ <a class="header-anchor" href="#q2-如何确认我下载的版本是最新的" aria-label="Permalink to &quot;Q2：如何确认我下载的版本是最新的？&quot;">​</a></h3><p>你可以手动检查当前版本是否为最新：</p><ul><li>进入 <strong>设置 → 关于</strong>，点击 <strong>&quot;检查更新&quot;</strong></li><li>如果当前版本支持应用内更新，按弹窗提示完成下载、安装和重启</li><li>或者直接访问 <a href="https://github.com/miaotouy/aio-hub/releases" target="_blank" rel="noreferrer">GitHub Releases 页面</a></li><li>推荐使用 <strong>Pre-release（预览版）</strong> 第一时间体验新功能</li></ul><h3 id="q3-代理已经配置了-但还是连不上-api" tabindex="-1">Q3：代理已经配置了，但还是连不上 API？ <a class="header-anchor" href="#q3-代理已经配置了-但还是连不上-api" aria-label="Permalink to &quot;Q3：代理已经配置了，但还是连不上 API？&quot;">​</a></h3><p>按以下顺序检查：</p><ol><li><strong>确认代理地址格式正确</strong>：应该像 <code>http://127.0.0.1:7897</code> 这样，不要漏掉 <code>http://</code></li><li><strong>确认代理服务正在运行</strong>：打开代理软件的界面，确认它正常工作</li><li><strong>测试代理连通性</strong>：在终端执行 <code>curl -x http://127.0.0.1:7897 https://api.openai.com/v1/models</code>（Windows 用户可以使用 PowerShell 的 <code>Invoke-WebRequest</code> 命令）</li><li><strong>尝试切换代理模式</strong>：有些代理软件需要切换到&quot;全局模式&quot;才能被非浏览器应用使用</li></ol><h3 id="q4-切换主题后界面显示异常" tabindex="-1">Q4：切换主题后界面显示异常？ <a class="header-anchor" href="#q4-切换主题后界面显示异常" aria-label="Permalink to &quot;Q4：切换主题后界面显示异常？&quot;">​</a></h3><p><strong>症状</strong>：从暗色主题切换到亮色主题（或反之）后，部分区域显示不正常。</p><p><strong>解决步骤</strong>：</p><ol><li>尝试 <strong>重启应用</strong>——大部分主题切换问题重启即可修复</li><li>如果问题持续，前往 <strong>设置 → 外观</strong>，手动切换一次主题模式</li><li>如果依然异常，尝试清除浏览器缓存（应用内缓存，不影响数据）：找到缓存目录并删除其中的内容 <ul><li>Windows：<code>%APPDATA%\\com.mty.aiohub\\cache</code></li><li>macOS：<code>~/Library/Caches/com.mty.aiohub</code></li><li>Linux：<code>~/.cache/com.mty.aiohub</code></li></ul></li></ol><h3 id="q5-聊天记录中有敏感信息-如何彻底清除" tabindex="-1">Q5：聊天记录中有敏感信息，如何彻底清除？ <a class="header-anchor" href="#q5-聊天记录中有敏感信息-如何彻底清除" aria-label="Permalink to &quot;Q5：聊天记录中有敏感信息，如何彻底清除？&quot;">​</a></h3><ol><li>在聊天工具中，找到对应的对话，点击删除即可</li><li>如果需要批量清除，可以在聊天管理页面选择多条对话进行删除</li><li>如果你希望彻底清除所有数据（包括配置），关闭应用后删除整个数据目录（见上文&quot;数据目录位置&quot;），重启应用即可 <blockquote><p>⚠️ 此操作不可逆，请先确认你不需要保留任何数据</p></blockquote></li></ol><h3 id="q6-用着用着界面变成了英文" tabindex="-1">Q6：用着用着界面变成了英文？ <a class="header-anchor" href="#q6-用着用着界面变成了英文" aria-label="Permalink to &quot;Q6：用着用着界面变成了英文？&quot;">​</a></h3><p><strong>症状</strong>：应用界面语言突然从中文变成了英文。</p><p><strong>原因</strong>：通常是自动检测系统语言时发生了切换，或者误触了语言设置。</p><p><strong>解决步骤</strong>：</p><ol><li>前往 <strong>设置 → 外观 → 语言</strong></li><li>选择 <strong>&quot;简体中文&quot;</strong></li><li>应用会自动切换回中文界面</li><li>如果还是没有变化，重启应用即可</li></ol><h3 id="q7-如何在旧版本之间迁移数据" tabindex="-1">Q7：如何在旧版本之间迁移数据？ <a class="header-anchor" href="#q7-如何在旧版本之间迁移数据" aria-label="Permalink to &quot;Q7：如何在旧版本之间迁移数据？&quot;">​</a></h3><p>如果你从非常早期的版本（v0.3.x 或更早）升级到最新版：</p><ol><li>先找到旧版本的数据目录并完整备份</li><li>安装新版本，首次运行后关闭应用</li><li>将备份的数据目录中的 <code>config.json</code> 和 <code>chat-history/</code> 等关键目录复制到新版本的数据目录中</li><li>启动应用，检查配置和聊天记录是否正常迁移</li></ol><blockquote><p>从 v0.4.x 版本开始，所有版本之间自动兼容，覆盖安装即可。</p></blockquote><h3 id="q8-应用卡住了-无法正常关闭怎么办" tabindex="-1">Q8：应用卡住了，无法正常关闭怎么办？ <a class="header-anchor" href="#q8-应用卡住了-无法正常关闭怎么办" aria-label="Permalink to &quot;Q8：应用卡住了，无法正常关闭怎么办？&quot;">​</a></h3><p><strong>Windows 用户</strong>：</p><ol><li>按 <code>Ctrl + Shift + Esc</code> 打开任务管理器</li><li>找到 <strong>AIO Hub</strong>，右键 → <strong>结束任务</strong></li><li>重新启动应用</li></ol><p><strong>macOS 用户</strong>：</p><ol><li>点击顶部菜单栏的苹果图标 → <strong>强制退出</strong></li><li>选择 <strong>AIO Hub</strong>，点击 <strong>&quot;强制退出&quot;</strong></li></ol><p><strong>通用方法</strong>：</p><ul><li>按 <code>Alt + F4</code>（Windows）或 <code>Cmd + Q</code>（macOS）强制退出</li><li>如果仍然无法关闭，重启电脑是最简单的解决方案</li></ul><hr><blockquote><p>以上方法都不能解决你的问题？请带上日志文件到 <a href="https://github.com/miaotouy/aio-hub/issues" target="_blank" rel="noreferrer">GitHub Issues</a> 反馈，附上详细的错误描述和出现问题的操作步骤，开发者会尽快回复你。</p></blockquote>',127)])])}const p=o(a,[["render",e]]);export{u as __pageData,p as default};
